async getTools(serverId: string): Promise<Record<string, unknown>> {
  const client = this.clients.get(serverId)
  if (!client) {
    throw new Error(`Server not connected: ${serverId}`)
  }

async connectServer(id: string): Promise<void> {
  const config = this.store.getById(id)
  if (!config) {
    throw new Error(`MCP server not found: ${id}`)
  }

updateServer(id: string, partial: Partial<McpServerConfigInput>): McpServerConfig {
  return this.store.update(id, partial)
}

getServer(id: string): McpServerConfig | undefined {
  return this.store.getById(id)
}

async connectEnabled(): Promise<void> {
  const enabled = this.store.getEnabled()
  const connections = enabled.map(config => this.clientManager.connect(config))
  await Promise.all(connections)
}

